const items = $input.all();
const resultados = [];

for (const item of items) { 
  const rawString = item.json.content.parts[0].text; 
  const cleanString = rawString.replace(/```json/g, '').replace(/```/g, '').trim(); 
  const parsedData = JSON.parse(cleanString);

  resultados.push(parsedData);
}

return resultados;

// 1. Obtenemos el JSON completo
const inputJson = $input.first().json;

// 2. Extracción Inteligente
const textoMasivo = (inputJson.body && inputJson.body.texto_masivo) 
                    ? inputJson.body.texto_masivo 
                    : inputJson.texto_masivo;

if (!textoMasivo) {
  throw new Error("No se detectó el 'texto_masivo'.");
}

// 3. Cortamos usando Regex universal para múltiples saltos de línea
const parrafos = textoMasivo.split(/\r?\n\s*\r?\n/);

// 4. Formateamos estrictamente como n8n exige para crear MÚLTIPLES ITEMS
const itemsSeparados = parrafos
  .filter(p => p.trim() !== '') 
  .map(p => {
    return {
      json: {
        prosa: p.trim()
      }
    };
  }); 

// 5. Devolvemos el array. n8n detectará mágicamente que son N items independientes.
return itemsSeparados;
